import React, { useState, useEffect } from "react";
import { Form, Button, Col, Row, Spinner } from "react-bootstrap";
import { useParams, useNavigate } from "react-router-dom";
import axios from "axios";
import Header from "../../components/Headers/Header";
import ReactQuill from "react-quill";
import "react-quill/dist/quill.snow.css";

const EditDrug = () => {
    const { id } = useParams();
    const navigate = useNavigate();

    const [drug, setDrug] = useState({
        medicine_code: "",
        medicine_name: "",
        medicine_type_id: "",
        medicine_type_name: "",
        price: "",
        unit: "",
        description: "",
    });

    const [medicineTypes, setMedicineTypes] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);
    const [isSaving, setIsSaving] = useState(false);

    useEffect(() => {
        const fetchData = async () => {
            try {
                await Promise.all([
                    fetchMedicine(),
                    fetchMedicineTypes()
                ]);
            } catch (error) {
                console.error("Error loading data:", error);
            } finally {
                setLoading(false);
            }
        };

        fetchData();
    }, [id]);

    const fetchMedicine = async () => {
        try {
            const response = await axios.get(`http://localhost:5001/api/medicine/${id}`);
            if (response.data) {
                setDrug({
                    medicine_code: response.data.medicine_code || "",
                    medicine_name: response.data.medicine_name || "",
                    medicine_type_id: response.data.medicine_type_id ? response.data.medicine_type_id.toString() : "",
                    medicine_type_name: response.data.medicine_type_name || "",
                    price: response.data.price ? response.data.price.toString() : "",
                    unit: response.data.unit || "",
                    description: response.data.description || "",
                });
            } else {
                setError("Dữ liệu thuốc không hợp lệ.");
            }
        } catch (error) {
            setError("Không tìm thấy thuốc hoặc có lỗi khi tải dữ liệu.");
        }
    };

    const fetchMedicineTypes = async () => {
        try {
            const response = await axios.get("http://localhost:5001/api/medicine-type");
            if (response.data && response.data.data) {
                setMedicineTypes(response.data.data);
            }
        } catch (error) {
            console.error("Error fetching medicine types:", error);
        }
    };

    const handleChange = (e) => {
        const { name, value } = e.target;
        setDrug((prev) => ({ ...prev, [name]: value }));
    };

    const handleDescriptionChange = (value) => {
        setDrug((prev) => ({ ...prev, description: value }));
    };

    const handleUpdate = async (e) => {
        e.preventDefault();

        if (!drug.medicine_code || !drug.medicine_name || !drug.medicine_type_id || !drug.price || !drug.unit) {
            alert("Vui lòng điền đầy đủ các trường bắt buộc!");
            return;
        }

        setIsSaving(true);
        try {
            const updateData = {
                medicine_code: drug.medicine_code,
                medicine_name: drug.medicine_name,
                medicine_type_id: drug.medicine_type_id ? parseInt(drug.medicine_type_id) : null,
                price: drug.price ? parseFloat(drug.price) : null,
                unit: drug.unit,
                description: drug.description,
            };

            await axios.put(`http://localhost:5001/api/medicine/${id}`, updateData);
            alert("Cập nhật thành công!");
            navigate("/drug");
        } catch (error) {
            alert(`Cập nhật thất bại! Lỗi: ${error.response?.data?.message || error.message}`);
        } finally {
            setIsSaving(false);
        }
    };

    const handleCancel = () => {
        navigate("/drug");
    };

    if (loading) {
        return (
            <>
                <Header />
                <div className="container mt-4 text-center">
                    <Spinner animation="border" role="status">
                        <span className="visually-hidden">Đang tải...</span>
                    </Spinner>
                    <p>Đang tải dữ liệu thuốc...</p>
                </div>
            </>
        );
    }

    if (error) {
        return (
            <>
                <Header />
                <div className="container mt-4">
                    <div className="alert alert-danger">{error}</div>
                    <Button variant="primary" onClick={() => navigate("/drug")}>
                        Quay lại danh sách thuốc
                    </Button>
                </div>
            </>
        );
    }

    return (
        <>
            <Header />
            <div className="container mt-4">
                <h4 className="mb-4" style={{ fontSize: "28px", fontWeight: "bold" }}>Chỉnh sửa thuốc</h4>
                <Form onSubmit={handleUpdate}>
                    <Row className="mb-3">
                        <Col md={6}>
                            <Form.Group controlId="medicineCode">
                                <Form.Label>Mã thuốc <span className="text-danger">*</span></Form.Label>
                                <Form.Control
                                    type="text"
                                    name="medicine_code"
                                    value={drug.medicine_code}
                                    onChange={handleChange}
                                    required
                                />
                            </Form.Group>
                        </Col>
                        <Col md={6}>
                            <Form.Group controlId="medicineName">
                                <Form.Label>Tên thuốc <span className="text-danger">*</span></Form.Label>
                                <Form.Control
                                    type="text"
                                    name="medicine_name"
                                    value={drug.medicine_name}
                                    onChange={handleChange}
                                    required
                                />
                            </Form.Group>
                        </Col>
                    </Row>
                    <Row className="mb-3">
                        <Col md={6}>
                            <Form.Group controlId="medicineTypeId">
                                <Form.Label>Loại thuốc <span className="text-danger">*</span></Form.Label>
                                <Form.Select
                                    name="medicine_type_id"
                                    value={drug.medicine_type_id}
                                    onChange={handleChange}
                                    required
                                >
                                    <option value="">Chọn loại thuốc</option>
                                    {medicineTypes.map(type => (
                                        <option key={type.id} value={type.id}>
                                            {type.medicine_type_name}
                                        </option>
                                    ))}
                                </Form.Select>
                            </Form.Group>
                        </Col>
                        <Col md={6}>
                            <Form.Group controlId="drugPrice">
                                <Form.Label>Giá <span className="text-danger">*</span></Form.Label>
                                <Form.Control
                                    type="number"
                                    name="price"
                                    value={drug.price}
                                    onChange={handleChange}
                                    required
                                    min="0"
                                />
                            </Form.Group>
                        </Col>
                    </Row>
                    <Row className="mb-3">
                        <Col md={6}>
                            <Form.Group controlId="drugUnit">
                                <Form.Label>Đơn vị <span className="text-danger">*</span></Form.Label>
                                <Form.Control
                                    type="text"
                                    name="unit"
                                    value={drug.unit}
                                    onChange={handleChange}
                                    required
                                />
                            </Form.Group>
                        </Col>
                    </Row>
                    <Form.Group controlId="drugDescription" className="mb-4">
                        <Form.Label>Mô tả <span className="text-danger">*</span></Form.Label>
                        <ReactQuill
                            theme="snow"
                            value={drug.description}
                            onChange={handleDescriptionChange}
                            style={{ height: '200px', marginBottom: '50px' }}
                        />
                    </Form.Group>
                    <div className="d-flex justify-content-end mt-5">
                        <Button
                            variant="secondary"
                            onClick={handleCancel}
                            className="me-2"
                            disabled={isSaving}
                        >
                            Quay lại
                        </Button>
                        <Button
                            variant="primary"
                            type="submit"
                            disabled={isSaving}
                        >
                            {isSaving ? (
                                <>
                                    <Spinner
                                        as="span"
                                        animation="border"
                                        size="sm"
                                        role="status"
                                        aria-hidden="true"
                                    />
                                    {' '}Đang lưu...
                                </>
                            ) : 'Lưu lại'}
                        </Button>
                    </div>
                </Form>
            </div>
        </>
    );
};

export default EditDrug;
